    // dolockOSThread is called by LockOSThread and lockOSThread below
    // after they modify m.locked. Do not allow preemption during this call,
    // or else the m might be different in this function than in the caller.
    //
    //go:nosplit
    void dolockOSThread()
    {
        if(GOARCH == "wasm"_s)
        {
            // no threads on wasm yet
            return;
        }
        auto gp = getg();
        rec::set(gocpp::recv(gp->m->lockedg), gp);
        rec::set(gocpp::recv(gp->lockedm), gp->m);
    }

    // LockOSThread wires the calling goroutine to its current operating system thread.
    // The calling goroutine will always execute in that thread,
    // and no other goroutine will execute in it,
    // until the calling goroutine has made as many calls to
    // [UnlockOSThread] as to LockOSThread.
    // If the calling goroutine exits without unlocking the thread,
    // the thread will be terminated.
    //
    // All init functions are run on the startup thread. Calling LockOSThread
    // from an init function will cause the main function to be invoked on
    // that thread.
    //
    // A goroutine should call LockOSThread before calling OS services or
    // non-Go library functions that depend on per-thread state.
    //
    //go:nosplit
    void LockOSThread()
    {
        if(atomic::Load(& newmHandoff.haveTemplateThread) == 0 && GOOS != "plan9"_s)
        {
            // If we need to start a new thread from the locked
            // thread, we need the template thread. Start it now
            // while we're in a known-good state.
            startTemplateThread();
        }
        auto gp = getg();
        gp->m->lockedExt++;
        if(gp->m->lockedExt == 0)
        {
            gp->m->lockedExt--;
            gocpp::panic("LockOSThread nesting overflow"_s);
        }
        dolockOSThread();
    }

    //go:nosplit
    void lockOSThread()
    {
        getg()->m->lockedInt++;
        dolockOSThread();
    }

    // dounlockOSThread is called by UnlockOSThread and unlockOSThread below
    // after they update m->locked. Do not allow preemption during this call,
    // or else the m might be in different in this function than in the caller.
    //
    //go:nosplit
    void dounlockOSThread()
    {
        if(GOARCH == "wasm"_s)
        {
            // no threads on wasm yet
            return;
        }
        auto gp = getg();
        if(gp->m->lockedInt != 0 || gp->m->lockedExt != 0)
        {
            return;
        }
        gp->m->lockedg = 0;
        gp->lockedm = 0;
    }

    // UnlockOSThread undoes an earlier call to LockOSThread.
    // If this drops the number of active LockOSThread calls on the
    // calling goroutine to zero, it unwires the calling goroutine from
    // its fixed operating system thread.
    // If there are no active LockOSThread calls, this is a no-op.
    //
    // Before calling UnlockOSThread, the caller must ensure that the OS
    // thread is suitable for running other goroutines. If the caller made
    // any permanent changes to the state of the thread that would affect
    // other goroutines, it should not call this function and thus leave
    // the goroutine locked to the OS thread until the goroutine (and
    // hence the thread) exits.
    //
    //go:nosplit
    void UnlockOSThread()
    {
        auto gp = getg();
        if(gp->m->lockedExt == 0)
        {
            return;
        }
        gp->m->lockedExt--;
        dounlockOSThread();
    }

    //go:nosplit
    void unlockOSThread()
    {
        auto gp = getg();
        if(gp->m->lockedInt == 0)
        {
            systemstack(badunlockosthread);
        }
        gp->m->lockedInt--;
        dounlockOSThread();
    }

    void badunlockosthread()
    {
        go_throw("runtime: internal error: misuse of lockOSThread/unlockOSThread"_s);
    }

    int32_t gcount()
    {
        auto n = int32_t(atomic::Loaduintptr(& allglen)) - sched.gFree.n - rec::Load(gocpp::recv(sched.ngsys));
        for(auto [gocpp_ignored, pp] : allp)
        {
            n -= pp->gFree.n;
        }

        // All these variables can be changed concurrently, so the result can be inconsistent.
        // But at least the current goroutine is running.
        if(n < 1)
        {
            n = 1;
        }
        return n;
    }

    int32_t mcount()
    {
        return int32_t(sched.mnext - sched.nmfreed);
    }

    struct gocpp_id_8
    {
        atomic::Uint32 signalLock;
        // Must hold signalLock to write. Reads may be lock-free, but
        // signalLock should be taken to synchronize with changes.
        atomic::Int32 hz;

        using isGoStruct = void;

        template<typename T> requires gocpp::GoStruct<T>
        operator T()
        {
            T result;
            result.signalLock = this->signalLock;
            result.hz = this->hz;
            return result;
        }

        template<typename T> requires gocpp::GoStruct<T>
        bool operator==(const T& ref) const
        {
            if (signalLock != ref.signalLock) return false;
            if (hz != ref.hz) return false;
            return true;
        }

        std::ostream& PrintTo(std::ostream& os) const
        {
            os << '{';
            os << "" << signalLock;
            os << " " << hz;
            os << '}';
            return os;
        }
    };

    std::ostream& operator<<(std::ostream& os, const struct gocpp_id_8& value)
    {
        return value.PrintTo(os);
    }


